-- الدفعة الأولى من ملء محتوى تصنيفات "تعلّم" الفارغة (status='draft')
-- تحت "اللغة العربية" (lugha-arabiyya) — تستنفد العنقود بالكامل
-- (8 تصنيفات فرعية من أصل 8، كلها بلا محتوى): الإملاء، النحو، الصرف،
-- البلاغة، فقه اللغة، المفردات الشرعية، مهارات فهم النصوص الشرعية،
-- تدريبات تطبيقية.
-- كل تصنيف يحصل على درس واحد حقيقي (lessons + lesson_sections +
-- lesson_citations)، مبني على مصادر معتمدة مسمّاة: الإملاء والترقيم في
-- الكتابة العربية لعبد العليم إبراهيم، النحو الواضح والبلاغة الواضحة
-- لعلي الجارم ومصطفى أمين، جامع الدروس العربية لمصطفى الغلاييني، شذا
-- العرف في فن الصرف لأحمد الحملاوي، فقه اللغة وسر العربية لأبي منصور
-- الثعالبي، المفردات في غريب القرآن للراغب الأصفهاني، علم أصول الفقه
-- لعبد الوهاب خلاف.
-- الآيات المستشهَد بها (القلم:1، يوسف:2، إبراهيم:4، الإسراء:88،
-- فصلت:3، الزخرف:3، محمد:24) تحقَّقت حرفياً من
-- artifacts/majalis/public/data/quran محلياً عبر حقل numberInSurah
-- قبل الإدراج (نُقل نص الآية بلا بسملة تصنيف اقتراني في بداية السورة).
-- الحديث الوحيد المستشهَد به «خيركم من تعلم القرآن وعلمه» (صحيح
-- البخاري رقم 5027، عثمان بن عفان رضي الله عنه) تحقَّق حرفياً عبر
-- WebSearch قبل الإدراج.
-- تصنيف "تدريبات تطبيقية" اكتُفي فيه باستشهادين كتابيين دون آية أو
-- حديث لطبيعته التطبيقية البحتة (لا نص شرعي مناسب دون تكلّف)، على غرار
-- سوابق مماثلة في دفعات سابقة.
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الثمانية عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) الإملاء
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='24380b36-87c8-4f43-b9e0-7a8bca0a7028' AND title='أساسيات الإملاء العربي: الهمزات والتاء والألف اللينة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أساسيات الإملاء العربي: الهمزات والتاء والألف اللينة', 'تعريف موجز بأهم قواعد الإملاء العربي التي يشيع الخطأ فيها: الهمزة المتطرفة، التاء المربوطة والمبسوطة، الألف المقصورة والممدودة', '24380b36-87c8-4f43-b9e0-7a8bca0a7028', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'الهمزة المتطرفة', 'تُكتب الهمزة المتطرفة (في آخر الكلمة) على حرف يناسب حركة ما قبلها: على الألف إن كان ما قبلها مفتوحًا (نشأ)، وعلى الواو إن كان مضمومًا (يجرُؤ)، وعلى الياء إن كان مكسورًا (قارِئ)، وعلى السطر مفردةً إن كان ما قبلها ساكنًا أو حرف مدّ (جزْء، سماء).', 1),
    (v_lesson, 'terms', 'التاء المربوطة والمبسوطة، والألف المقصورة والممدودة', 'التاء المربوطة (ة) تُنطق هاءً عند الوقف وتاءً عند الوصل، وتكون غالبًا في آخر الاسم المفرد المؤنث (مدرسة)، بخلاف التاء المبسوطة (ت) التي تُنطق تاءً دائمًا وتكون في الأفعال وبعض الأسماء (كتبتْ، بيت). أما الألف اللينة في آخر الكلمة فتُكتب مقصورة (ى) في أسماء وأفعال بعينها كـ"مصطفى" و"سعى"، وممدودة (ا) في أخرى كـ"عصا" و"دعا"، بحسب أصل الألف وموقعها.', 2),
    (v_lesson, 'evidence', 'الكتابة والتسطير في القرآن', 'أقسم الله تعالى بالقلم وما يخطّه من كتابة، فقال: ﴿ن ۚ وَالْقَلَمِ وَمَا يَسْطُرُونَ﴾ (القلم: 1)، وفي هذا القسَم تنويه بمنزلة الكتابة والتدوين، ومنها ضبط رسم الكلمات وقواعد إملائها.', 3);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الإملاء والترقيم في الكتابة العربية — عبد العليم إبراهيم', 1);
  END IF;

  -- 2) النحو
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='dc618b5e-539b-4858-b2ea-8a477ff7d89f' AND title='أساسيات النحو العربي: الإعراب وأثره في المعنى') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أساسيات النحو العربي: الإعراب وأثره في المعنى', 'تعريف موجز بنشأة علم النحو والفرق بين الجملة الاسمية والفعلية وأثر الإعراب في تغيير معنى الجملة', 'dc618b5e-539b-4858-b2ea-8a477ff7d89f', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'نشأة علم النحو', 'يُنسب وضع أول قواعد علم النحو إلى أبي الأسود الدؤلي في القرن الأول الهجري، بعد أن كثر اللحن (الخطأ في الإعراب) في ألسنة من دخلوا الإسلام من غير العرب، فخشي على سلامة قراءة القرآن الكريم من الخطأ، فوضع أصولاً لضبط أواخر الكلمات، طوّرها من بعده تلامذته والبصريون والكوفيون حتى استوى علمًا مستقلاً بأبوابه.', 1),
    (v_lesson, 'terms', 'الجملة الاسمية والفعلية وأثر الإعراب', 'الجملة الاسمية تبدأ باسم (مبتدأ وخبر) نحو "العلمُ نورٌ"، والجملة الفعلية تبدأ بفعل (فعل وفاعل) نحو "طلب الطالبُ العلمَ". وللإعراب أثر مباشر في المعنى: ففي "أكرمَ محمدٌ خالدًا" الفاعل هو محمد، بينما تغيير الحركات إلى "أكرمَ محمدًا خالدٌ" يقلب المعنى فيصبح خالد هو الفاعل، مما يبيّن أن الحركة الإعرابية ليست زخرفًا لفظيًا بل حاملة للمعنى.', 2),
    (v_lesson, 'evidence', 'القرآن عربي مبين', 'قال تعالى: ﴿إِنَّا أَنزَلْنَاهُ قُرْآنًا عَرَبِيًّا لَّعَلَّكُمْ تَعْقِلُونَ﴾ (يوسف: 2)، وضبط قواعد الإعراب من أهم الوسائل التي تُعين على سلامة تلاوة القرآن وفهم معانيه على الوجه الصحيح.', 3);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'النحو الواضح في قواعد اللغة العربية — علي الجارم ومصطفى أمين', 1),
    (v_lesson, 'book', 'جامع الدروس العربية — مصطفى الغلاييني', 2);
  END IF;

  -- 3) الصرف
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='2ed1c496-bbce-4d43-b0a2-0690dc323d23' AND title='علم الصرف: الميزان الصرفي وأوزان المشتقات') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('علم الصرف: الميزان الصرفي وأوزان المشتقات', 'تعريف موجز بعلم الصرف والفرق بينه وبين النحو، والميزان الصرفي، وأبرز صيغ المشتقات', '2ed1c496-bbce-4d43-b0a2-0690dc323d23', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريف الصرف والفرق بينه وبين النحو', 'علم الصرف هو العلم الذي يُعنى ببِنية الكلمة وصيغتها قبل دخولها في التركيب، بخلاف النحو الذي يُعنى بموقع الكلمة في الجملة وأثر ذلك في حركة آخرها. فالصرف يبحث في كيفية اشتقاق "كاتب" و"مكتوب" و"كتابة" من الجذر "كتب"، بينما النحو يبحث في إعراب هذه الكلمات بعد وضعها في جملة.', 1),
    (v_lesson, 'terms', 'الميزان الصرفي وصيغ المشتقات', 'يُستخدم الميزان الصرفي (فَعَلَ) لضبط وزن الكلمة، فوزن "كاتب" هو "فاعل"، ووزن "مكتوب" هو "مفعول". ومن أبرز المشتقات: اسم الفاعل (كاتب) الدال على من قام بالفعل، واسم المفعول (مكتوب) الدال على من وقع عليه الفعل، والفعل الثلاثي المجرد (كتب) والمزيد بحرف أو أكثر (كاتَب، اكتتب).', 2),
    (v_lesson, 'evidence', 'اللسان وسيلة البيان', 'قال تعالى: ﴿وَمَا أَرْسَلْنَا مِن رَّسُولٍ إِلَّا بِلِسَانِ قَوْمِهِ لِيُبَيِّنَ لَهُمْ﴾ (إبراهيم: 4)، وضبط بنية الكلمة العربية وصيغها من أهم أدوات تحقيق البيان الذي ذكرته الآية.', 3);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'شذا العرف في فن الصرف — أحمد الحملاوي', 1);
  END IF;

  -- 4) البلاغة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='77430cc1-7a52-43a6-a2e3-482aae5d5d6f' AND title='علم البلاغة: المعاني والبيان والبديع') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('علم البلاغة: المعاني والبيان والبديع', 'تعريف موجز بعلم البلاغة وأقسامه الثلاثة مع أمثلة على التشبيه والاستعارة والكناية', '77430cc1-7a52-43a6-a2e3-482aae5d5d6f', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريف البلاغة وأقسامها', 'البلاغة هي مطابقة الكلام لمقتضى الحال مع فصاحته، وتنقسم إلى ثلاثة علوم: علم المعاني (يبحث في أحوال الكلام من حيث مطابقته لمقتضى الحال، كالتقديم والتأخير والحذف)، وعلم البيان (يبحث في طرق إيراد المعنى الواحد بصور مختلفة كالتشبيه والاستعارة والكناية)، وعلم البديع (يبحث في وجوه تحسين الكلام لفظًا ومعنى كالجناس والطباق).', 1),
    (v_lesson, 'terms', 'أمثلة من التشبيه والاستعارة والكناية', 'التشبيه: عقد مقارنة بين شيئين بأداة تشبيه، نحو "العلمُ كالنور يبدد الجهل". الاستعارة: تشبيه حُذف أحد طرفيه، نحو "رأيت أسدًا يتكلم" أُريد بها الرجل الشجاع. الكناية: التعبير عن معنى بلازمه دون تصريح به، نحو "فلان طويل النجاد" كناية عن طول القامة.', 2),
    (v_lesson, 'evidence', 'إعجاز القرآن البلاغي', 'قال تعالى: ﴿قُل لَّئِنِ اجْتَمَعَتِ الْإِنسُ وَالْجِنُّ عَلَىٰ أَن يَأْتُوا بِمِثْلِ هَٰذَا الْقُرْآنِ لَا يَأْتُونَ بِمِثْلِهِ وَلَوْ كَانَ بَعْضُهُمْ لِبَعْضٍ ظَهِيرًا﴾ (الإسراء: 88)، وهذا التحدي القرآني الصريح كان من أبرز الدوافع التاريخية لنشأة علم البلاغة العربية عند علماء المسلمين لبيان وجوه إعجاز القرآن.', 3);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'البلاغة الواضحة — علي الجارم ومصطفى أمين', 1);
  END IF;

  -- 5) فقه اللغة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='fd5e06b4-2f71-4ec8-9621-47b4be9ae61e' AND title='فقه اللغة: خصائص العربية ونشأتها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('فقه اللغة: خصائص العربية ونشأتها', 'تعريف موجز بعلم فقه اللغة وموضوعه، وأبرز خصائص اللغة العربية كالاشتقاق والترادف والمشترك اللفظي', 'fd5e06b4-2f71-4ec8-9621-47b4be9ae61e', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريف فقه اللغة', 'فقه اللغة علم يبحث في نشأة اللغة العربية وتطورها ولهجاتها وخصائصها العامة، بخلاف علمَي النحو والصرف اللذين يُعنَيان بقواعد ضبط الكلمة والجملة. ومن أبرز موضوعاته: أصل اللغة العربية، اللهجات العربية القديمة قبل توحدها في لغة القرآن الفصحى، وخصائصها الذاتية التي تميزها عن غيرها من اللغات.', 1),
    (v_lesson, 'terms', 'خصائص اللغة العربية', 'من أبرز خصائص العربية: الاشتقاق، أي توليد كلمات جديدة من جذر واحد (كتب، كاتب، مكتوب، مكتبة)، والترادف، أي تعدد الألفاظ للمعنى الواحد (السيف، الحسام، المهند)، والمشترك اللفظي، أي دلالة اللفظ الواحد على أكثر من معنى بحسب السياق (كلمة "عين" تدل على عين الماء وعين الإنسان والجاسوس).', 2),
    (v_lesson, 'evidence', 'وصف القرآن بالعربية', 'قال تعالى: ﴿كِتَابٌ فُصِّلَتْ آيَاتُهُ قُرْآنًا عَرَبِيًّا لِّقَوْمٍ يَعْلَمُونَ﴾ (فصلت: 3)، ووصف القرآن بالعربية في غير موضع من كتاب الله من أبرز ما دفع علماء المسلمين إلى العناية بدراسة خصائص هذه اللغة ونشأتها.', 3);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'فقه اللغة وسر العربية — أبو منصور الثعالبي', 1);
  END IF;

  -- 6) المفردات الشرعية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='667f496f-ea50-4978-80e6-b7d77b7a05ad' AND title='المفردات الشرعية: دلالات الألفاظ القرآنية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('المفردات الشرعية: دلالات الألفاظ القرآنية', 'تعريف موجز بأهمية ضبط المعنى اللغوي والشرعي للمفردات القرآنية، بأمثلة من ألفاظ العبادات', '667f496f-ea50-4978-80e6-b7d77b7a05ad', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'أهمية ضبط معاني المفردات الشرعية', 'كثير من ألفاظ العبادات في القرآن لها معنى لغوي عام تطوّر إلى معنى شرعي خاص، فمعرفة الفرق بينهما ضرورية لفهم النص الشرعي على وجهه الصحيح؛ فمثلاً لفظ "الصلاة" في أصل اللغة يعني الدعاء، ثم صار في الاصطلاح الشرعي اسمًا للعبادة المخصوصة ذات الأقوال والأفعال المفتتحة بالتكبير والمختتمة بالتسليم.', 1),
    (v_lesson, 'terms', 'أمثلة أخرى: الزكاة والصيام', 'لفظ "الزكاة" في اللغة يعني النماء والطهارة، وفي الشرع صار اسمًا لحق مالي مفروض في مال مخصوص يُدفع لمستحقيه. ولفظ "الصيام" في اللغة يعني الإمساك مطلقًا، وفي الشرع صار اسمًا للإمساك عن المفطرات من طلوع الفجر إلى غروب الشمس بنية مخصوصة. وهذا الانتقال من المعنى اللغوي العام إلى المعنى الشرعي الخاص هو ما يبحثه علم المفردات الشرعية.', 2),
    (v_lesson, 'evidence', 'وصف القرآن بالعربية', 'قال تعالى: ﴿إِنَّا جَعَلْنَاهُ قُرْآنًا عَرَبِيًّا لَّعَلَّكُمْ تَعْقِلُونَ﴾ (الزخرف: 3)، وفهم دلالات ألفاظه العربية بدقة هو الطريق إلى تحقيق التعقل والفهم الذي ذكرته الآية.', 3);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المفردات في غريب القرآن — الراغب الأصفهاني', 1);
  END IF;

  -- 7) مهارات فهم النصوص الشرعية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='56a27bdc-721c-4f0c-90ef-23c41c6cb07c' AND title='مهارات فهم النصوص الشرعية: دلالات الألفاظ عند الأصوليين') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('مهارات فهم النصوص الشرعية: دلالات الألفاظ عند الأصوليين', 'تعريف موجز بأبرز أدوات فهم النص الشرعي عند علماء أصول الفقه: الحقيقة والمجاز، والعام والخاص', '56a27bdc-721c-4f0c-90ef-23c41c6cb07c', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'الحقيقة والمجاز', 'الحقيقة هي اللفظ المستعمل فيما وُضع له في أصل اللغة، والمجاز هو اللفظ المستعمل في غير ما وُضع له لعلاقة بينهما مع قرينة تمنع إرادة المعنى الأصلي. ومعرفة الفرق بينهما ضرورية لعدم حمل النص الشرعي على معنى غير مراد، كما في قوله تعالى عن الوالدين: ﴿وَاخْفِضْ لَهُمَا جَنَاحَ الذُّلِّ مِنَ الرَّحْمَةِ﴾، فـ"جناح الذل" مجاز عن التواضع لا حقيقة له.', 1),
    (v_lesson, 'terms', 'العام والخاص والمطلق والمقيد', 'اللفظ العام يستغرق جميع أفراده دفعة واحدة بلا حصر، نحو "الناس"، بينما الخاص يدل على فرد معين أو أفراد محصورين. واللفظ المطلق يدل على الماهية بلا قيد، نحو "رقبة" في كفارة اليمين، والمقيد يدل عليها بقيد زائد، نحو "رقبة مؤمنة" في كفارة القتل. وضبط هذه الفروق من أهم أدوات علماء أصول الفقه في استنباط الأحكام من النصوص الشرعية.', 2),
    (v_lesson, 'evidence', 'الأمر بتدبر القرآن', 'قال تعالى: ﴿أَفَلَا يَتَدَبَّرُونَ الْقُرْآنَ أَمْ عَلَىٰ قُلُوبٍ أَقْفَالُهَا﴾ (محمد: 24)، وفهم دلالات الألفاظ بدقة هو أحد أهم أبواب التدبر الذي دعت إليه الآية.', 3),
    (v_lesson, 'evidence', 'فضل تعلم القرآن وتعليمه', 'عن عثمان بن عفان رضي الله عنه أن النبي صلى الله عليه وسلم قال: «خَيْرُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُ»، رواه البخاري.', 4);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'علم أصول الفقه — عبد الوهاب خلاف', 1),
    (v_lesson, 'book', 'صحيح البخاري، كتاب فضائل القرآن، رقم 5027', 2);
  END IF;

