    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'نموذج إعرابي تطبيقي', 'مثال: "إنَّ العلمَ نورٌ يهدي صاحبَه". إعرابه: "إنّ" حرف توكيد ونصب، "العلمَ" اسم "إنّ" منصوب وعلامة نصبه الفتحة، "نورٌ" خبر "إنّ" مرفوع وعلامة رفعه الضمة، وجملة "يهدي صاحبَه" في محل رفع نعت لـ"نور"، و"صاحبَه" مفعول به منصوب وعلامة نصبه الفتحة والهاء ضمير متصل مضاف إليه في محل جر.', 1),
    (v_lesson, 'terms', 'نموذج تطبيقي على الصرف والإملاء', 'مثال صرفي: كلمة "مُتَعَلِّم" على وزن "مُتَفَعِّل"، اسم فاعل من الفعل الخماسي "تعلّم". مثال إملائي: التمييز بين "لأنّه" (بهمزة قطع لأنها همزة "أنّ" المؤكدة) و"لإنّه" الخطأ الشائع، وبين "هؤلاء" و"هؤلآء" الخطأ الشائع في رسم الهمزة على الألف بعد الواو.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'النحو الواضح في قواعد اللغة العربية — علي الجارم ومصطفى أمين', 1),
    (v_lesson, 'book', 'جامع الدروس العربية — مصطفى الغلاييني', 2);
  END IF;

